sql:
SELECT AVG(profit) AS average_profit
FROM economic_data
WHERE data_quality = 'high';

SELECT data_id, profit_d, profit_f
FROM economic_data
WHERE profit_d > 0 AND profit_f > 0;

SELECT inventory_id, data_id
FROM inventory_data
WHERE inventory = 92.4;

SELECT year, profit_d, profit_f, inventory
FROM economic_data
WHERE profit_f > profit_d AND inventory < (SELECT AVG(inventory) FROM economic_data);

SELECT pce
FROM economic_data
WHERE data_id = 1;

SELECT year, profit, profit_d, profit_f, fi_nonres, fi_res, pce, inventory
FROM economic_data
WHERE year BETWEEN 2010 AND 2020;

SELECT profit, inventory, fi_nonres, fi_res, region_id, sector_id
FROM economic_data
WHERE profit < 100 AND data_quality = 'High';

SELECT DISTINCT region_id 
FROM economic_data 
WHERE created_at > '2020-01-01';

SELECT year, profit, (profit - (SELECT AVG(profit) FROM economic_data)) AS profit_difference
FROM economic_data
WHERE region_id = 1 AND sector_id = 2;

external_knowledge:
- 'stockpile' refers to the inventory levels;
- 'yearly earnings' refers to the profit for each year;
- 'above average' indicates that the profit for those years exceeds the overall average profit.

